+//! Accelerate Framework Matmul (Routes to ANE automatically)
+//!
+//! Uses CBLAS (part of Accelerate) for matrix multiplication.
+//! Apple's Accelerate automatically routes small-batch matmul to Neural Engine.
+//!
+//! Key advantages:
+//! 1. Simple C API - just one function call
+//! 2. Zero overhead - no graph compilation, no wrappers
+//! 3. Proven ANE routing - Apple uses this everywhere
+//! 4. Works with BF16 via conversion (or use vDSP for BF16 native)
+//!
+//! This is the SIMPLEST way to use ANE without Core ML.
+
+const std = @import("std");
+const BF16 = @import("gguf_loader.zig").BF16;
+
+const log = std.log.scoped(.accelerate_matmul);
+
+// Accelerate C API
+pub const c = struct {
+    // We'll use FP32 internally since Accelerate CBLAS works with float
+    // BF16 → FP32 → matmul → FP32 → BF16
+    // ANE will still be used for the FP32 matmul
+
+    extern "c" fn cblas_sgemm(
+        order: c_int,  // CblasRowMajor = 101
+        transA: c_int, // CblasNoTrans = 111
+        transB: c_int,
+        m: c_int,
+        n: c_int,
+        k: c_int,
+        alpha: f32,
+        A: [*]const f32,
+        lda: c_int,
+        B: [*]const f32,
+        ldb: c_int,
+        beta: f32,
+        C: [*]f32,
+        ldc: c_int,
+    ) void;
+};
+
+/// Accelerate Matmul Engine
+pub const AccelerateMatmulEngine = struct {
+    allocator: std.mem.Allocator,
+
+    // Temporary FP32 buffers (reused to avoid allocations)
+    temp_a: ?[]f32 = null,
+    temp_b: ?[]f32 = null,
+    temp_c: ?[]f32 = null,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator) !*Self {
+        log.info("Initializing Accelerate Matmul Engine (Auto ANE routing)", .{});
+
+        const self = try allocator.create(Self);
+        self.* = Self{
+            .allocator = allocator,
+        };
+
+        log.info("Accelerate ready - cblas_sgemm will auto-route to ANE for M=1", .{});
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        if (self.temp_a) |buf| self.allocator.free(buf);
+        if (self.temp_b) |buf| self.allocator.free(buf);
+        if (self.temp_c) |buf| self.allocator.free(buf);
+        self.allocator.destroy(self);
+    }
+
+    /// Convert BF16 to FP32
+    inline fn bf16ToF32(bf16: BF16) f32 {
+        // BF16: sign(1) + exp(8) + mantissa(7)
+        // FP32: sign(1) + exp(8) + mantissa(23)
+        // Conversion: just shift left 16 bits
+        const bits: u32 = @as(u32, bf16) << 16;
+        return @bitCast(bits);
+    }
+
+    /// Convert FP32 to BF16 (round to nearest)
+    inline fn f32ToBF16(f32_val: f32) BF16 {
+        const bits: u32 = @bitCast(f32_val);
+        // Round to nearest: add 0x7FFF before truncating
+        const rounded = bits + 0x7FFF;
+        return @truncate(rounded >> 16);
+    }
+
+    /// Matrix multiplication: C = A × B
+    ///
+    /// Uses Accelerate framework which automatically routes to:
+    /// - ANE: For M=1-8 (low power, good latency)
+    /// - AMX: For larger M on Apple Silicon
+    /// - CPU: Fallback
+    pub fn matmul(
+        self: *Self,
+        a: []const BF16,  // [M, K]
+        b: []const BF16,  // [K, N]
+        c_out: []BF16,    // [M, N] output
+        m: u32,
+        k: u32,
+        n: u32,
+    ) !void {
+        const m_size = @as(usize, m) * k;
+        const b_size = @as(usize, k) * n;
+        const c_size = @as(usize, m) * n;
+
+        // Allocate or reuse FP32 buffers
+        if (self.temp_a == null or self.temp_a.?.len < m_size) {
+            if (self.temp_a) |buf| self.allocator.free(buf);
+            self.temp_a = try self.allocator.alloc(f32, m_size);
+        }
+        if (self.temp_b == null or self.temp_b.?.len < b_size) {
+            if (self.temp_b) |buf| self.allocator.free(buf);
+            self.temp_b = try self.allocator.alloc(f32, b_size);
+        }
+        if (self.temp_c == null or self.temp_c.?.len < c_size) {
+            if (self.temp_c) |buf| self.allocator.free(buf);
+            self.temp_c = try self.allocator.alloc(f32, c_size);
+        }
+
+        const a_f32 = self.temp_a.?[0..m_size];
+        const b_f32 = self.temp_b.?[0..b_size];
+        const c_f32 = self.temp_c.?[0..c_size];
+
+        // Convert BF16 → FP32
+        for (a, 0..) |val, i| {
+            a_f32[i] = bf16ToF32(val);
+        }
+        for (b, 0..) |val, i| {
+            b_f32[i] = bf16ToF32(val);
+        }
+
+        // Call Accelerate CBLAS matmul
+        // This will automatically route to ANE for M=1!
+        const CblasRowMajor: c_int = 101;
+        const CblasNoTrans: c_int = 111;
+
+        c.cblas_sgemm(
+            CblasRowMajor,
+            CblasNoTrans,  // A is not transposed
+            CblasNoTrans,  // B is not transposed
+            @intCast(m),   // rows of A and C
+            @intCast(n),   // cols of B and C
+            @intCast(k),   // cols of A, rows of B
+            1.0,           // alpha (scale factor for AB)
+            a_f32.ptr,
+            @intCast(k),   // leading dimension of A (cols)
+            b_f32.ptr,
+            @intCast(n),   // leading dimension of B (cols)
+            0.0,           // beta (scale factor for C, 0 means overwrite)
+            c_f32.ptr,
+            @intCast(n),   // leading dimension of C (cols)
+        );
+
+        // Convert FP32 → BF16
+        for (c_f32[0..c_size], 0..) |val, i| {
+            c_out[i] = f32ToBF16(val);
+        }
+
+        log.debug("Accelerate matmul [{}, {}] × [{}, {}] completed (auto-routed)", .{
+            m, k, k, n,
+        });
+    }
+
+    /// QKV projection: [1, hidden] × [hidden, hidden] = [1, hidden]
+    pub fn matmulQKV(
+        self: *Self,
+        hidden_state: []const BF16,
+        weight: []const BF16,
+        output: []BF16,
+        hidden_size: u32,
+    ) !void {
+        return self.matmul(hidden_state, weight, output, 1, hidden_size, hidden_size);
+    }
+
+    /// FFN gate projection: [1, hidden] × [hidden, intermediate]
+    pub fn matmulFFNGate(
+        self: *Self,
+        hidden_state: []const BF16,
+        weight: []const BF16,
+        output: []BF16,
+        hidden_size: u32,
+        intermediate_size: u32,
+    ) !void {
+        return self.matmul(hidden_state, weight, output, 1, hidden_size, intermediate_size);
+    }
+
+    /// FFN down projection: [1, intermediate] × [intermediate, hidden]
+    pub fn matmulFFNDown(
+        self: *Self,
+        intermediate: []const BF16,
+        weight: []const BF16,
+        output: []BF16,
+        intermediate_size: u32,
+        hidden_size: u32,
+    ) !void {
+        return self.matmul(intermediate, weight, output, 1, intermediate_size, hidden_size);
+    }
+};

