+//! Direct MPS Matrix Multiplication (No MPSGraph overhead)
+//!
+//! Uses MPSMatrixMultiplication kernel directly for Neural Engine routing.
+//! This approach has MUCH lower overhead than MPSGraph because:
+//! 1. No graph compilation
+//! 2. No NDArray wrapping
+//! 3. No feed dictionaries
+//! 4. Direct Metal buffer → MPS kernel → Neural Engine
+//!
+//! MPS automatically routes small-batch matmul (M=1-8) to Neural Engine.
+
+const std = @import("std");
+
+pub const c = struct {
+    extern "objc" fn objc_getClass(name: [*:0]const u8) ?*anyopaque;
+    extern "objc" fn objc_msgSend() void;
+    extern "objc" fn sel_registerName(name: [*:0]const u8) *anyopaque;
+    extern "objc" fn objc_retain(obj: *anyopaque) *anyopaque;
+    extern "objc" fn objc_release(obj: *anyopaque) void;
+};
+
+// Calling convention helpers
+fn msgSend0(comptime T: type) *const fn (*anyopaque, *anyopaque) callconv(.c) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+fn msgSend1(comptime T: type, comptime P1: type) *const fn (*anyopaque, *anyopaque, P1) callconv(.c) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+fn msgSend2(comptime T: type, comptime P1: type, comptime P2: type) *const fn (*anyopaque, *anyopaque, P1, P2) callconv(.c) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+fn msgSend3(comptime T: type, comptime P1: type, comptime P2: type, comptime P3: type) *const fn (*anyopaque, *anyopaque, P1, P2, P3) callconv(.c) T {
+    return @ptrCast(&c.objc_msgSend);
+}
+
+/// Create MPSMatrixDescriptor for BF16 matrix
+pub fn createMatrixDescriptor(rows: u64, cols: u64, row_bytes: u64) *anyopaque {
+    const MPSMatrixDescriptorClass = c.objc_getClass("MPSMatrixDescriptor") orelse unreachable;
+    const sel_matrixDescriptorWithRows = c.sel_registerName("matrixDescriptorWithRows:columns:rowBytes:dataType:");
+
+    const call = msgSend3(
+        *anyopaque,
+        u64, // rows
+        u64, // columns
+        u64, // rowBytes
+    );
+
