+
+/// Create MPSMatrix from Metal buffer
+pub fn createMatrix(
+    device: *anyopaque,
+    descriptor: *anyopaque,
+    buffer: *anyopaque,
+    offset: u64,
+) *anyopaque {
+    const MPSMatrixClass = c.objc_getClass("MPSMatrix") orelse unreachable;
+    const sel_initWithBuffer = c.sel_registerName("initWithBuffer:offset:descriptor:");
+
+    const alloc_sel = c.sel_registerName("alloc");
+    const alloc = msgSend0(*anyopaque);
+    const matrix = alloc(MPSMatrixClass, alloc_sel);
+
+    const init = msgSend3(
+        *anyopaque,
+        *anyopaque, // buffer
+        u64,        // offset
+        *anyopaque, // descriptor
+    );
+
+    return init(matrix, sel_initWithBuffer, buffer, offset, descriptor);
+}
+
+/// Create MPSMatrixMultiplication kernel
+/// This kernel will automatically route to Neural Engine for M=1 cases
+pub fn createMatmulKernel(
+    device: *anyopaque,
+    result_rows: u64,
+    result_cols: u64,
+    interior_cols: u64,
+    alpha: f64,
+    beta: f64,
+) *anyopaque {
+    const MPSMatrixMultiplicationClass = c.objc_getClass("MPSMatrixMultiplication") orelse unreachable;
+    const sel_initWithDevice = c.sel_registerName("initWithDevice:resultRows:resultColumns:interiorColumns:");
+
+    const alloc_sel = c.sel_registerName("alloc");
+    const alloc = msgSend0(*anyopaque);
+    const kernel_obj = alloc(MPSMatrixMultiplicationClass, alloc_sel);
+
+    const init = msgSend3(
+        *anyopaque,
+        *anyopaque, // device
+        u64,        // resultRows
+        u64,        // resultColumns
+    );
+
+    _ = init(kernel_obj, sel_initWithDevice, device, result_rows, result_cols);
+
+    // Set alpha and beta (for C = alpha*AB + beta*C, usually alpha=1, beta=0)
+    _ = alpha; // TODO: set these if needed
+    _ = beta;
+
+    return kernel_obj;
+}
+
+/// Encode matmul into command buffer
+/// C = A × B
+pub fn encodeMatmul(
+    kernel: *anyopaque,
+    command_buffer: *anyopaque,
+    matrix_a: *anyopaque,
+    matrix_b: *anyopaque,
+    matrix_c: *anyopaque,
+) void {
+    const sel_encodeToCommandBuffer = c.sel_registerName("encodeToCommandBuffer:leftMatrix:rightMatrix:resultMatrix:");
+
+    const encode = msgSend3(
+        void,
+        *anyopaque, // commandBuffer
+        *anyopaque, // leftMatrix
+        *anyopaque, // rightMatrix
+    );
+
+    encode(kernel, sel_encodeToCommandBuffer, command_buffer, matrix_a, matrix_b, matrix_c);
+}

