+//! Simple C wrapper for MPSGraph to avoid Zig msgSend issues
+
+#import <Foundation/Foundation.h>
+#import <Metal/Metal.h>
+#import <MetalPerformanceShadersGraph/MetalPerformanceShadersGraph.h>
+
+// Global MPSGraphDevice (created once, shared)
+static MPSGraphDevice *g_graphDevice = nil;
+
+// C API exports
+
+void* mps_graph_device_create(void* mtlDevice) {
+    id<MTLDevice> device = (__bridge id<MTLDevice>)mtlDevice;
+    // Use class factory method instead of init
+    MPSGraphDevice *graphDevice = [MPSGraphDevice deviceWithMTLDevice:device];
+    g_graphDevice = graphDevice; // Keep global reference
+    return (__bridge_retained void*)graphDevice;
+}
+
+void* mps_graph_create(void) {
+    MPSGraph *graph = [[MPSGraph alloc] init];
+    return (__bridge_retained void*)graph;
+}
+
+void mps_graph_release(void* graph) {
+    MPSGraph *g = (__bridge_transfer MPSGraph*)graph;
+    (void)g; // ARC will release
+}
+
+void* mps_graph_placeholder_create(
+    void* graph,
+    const uint32_t* shape_dims,
+    size_t shape_len,
+    uint32_t dataType,
+    const char* name
+) {
+    @autoreleasepool {
+        MPSGraph *g = (__bridge MPSGraph*)graph;
+
+        // Create shape array
+        NSMutableArray *shapeArray = [NSMutableArray arrayWithCapacity:shape_len];
+        for (size_t i = 0; i < shape_len; i++) {
+            [shapeArray addObject:[NSNumber numberWithUnsignedInt:shape_dims[i]]];
+        }
+
+        NSString *nameStr = [NSString stringWithUTF8String:name];
+
+        MPSGraphTensor *tensor = [g placeholderWithShape:shapeArray
+                                               dataType:(MPSDataType)dataType
+                                                   name:nameStr];
+
+        return (__bridge_retained void*)tensor;
+    }
+}
+
+void* mps_graph_matmul(
+    void* graph,
+    void* inputTensor,
+    void* weightTensor,
+    const char* name
+) {
+    @autoreleasepool {
+        MPSGraph *g = (__bridge MPSGraph*)graph;
+        MPSGraphTensor *input = (__bridge MPSGraphTensor*)inputTensor;
+        MPSGraphTensor *weight = (__bridge MPSGraphTensor*)weightTensor;
+
+        NSString *nameStr = [NSString stringWithUTF8String:name];
+
+        MPSGraphTensor *output = [g matrixMultiplicationWithPrimaryTensor:input
+                                                          secondaryTensor:weight
+                                                                     name:nameStr];
+
+        return (__bridge_retained void*)output;
+    }
+}

