+///! GPU vs NPU Matmul Comparison
+///!
+///! Direct comparison of:
+///! 1. GPU matmul using Metal shaders
+///! 2. NPU matmul using MPSGraph
+///!
+///! This will show if NPU is actually faster for our use case.
+
+const std = @import("std");
+const metal = @import("inference/metal_inference.zig");
+const model = @import("inference/qwen_model.zig");
+const BF16 = @import("inference/gguf_loader.zig").BF16;
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n=== GPU vs NPU Matmul Comparison ===\n\n", .{});
+
+    // Create config
+    const config = model.QwenConfig{
+        .hidden_size = 5120,
+        .num_attention_heads = 40,
+        .num_key_value_heads = 8,
+        .intermediate_size = 27648,
+        .n_layers = 64,
+        .vocab_size = 152064,
+        .max_seq_len = 32768,
+        .head_dim = 128,
+        .kv_dim = 1024,
+        .rms_norm_eps = 1e-6,
+    };
+
+    std.debug.print("Model: Qwen2.5-32B\n", .{});
+    std.debug.print("  Hidden size: {}\n", .{config.hidden_size});
+    std.debug.print("  Intermediate size: {}\n", .{config.intermediate_size});
+    std.debug.print("\n", .{});
+
+    // Initialize Metal engine
+    std.debug.print("Initializing Metal engine...\n", .{});
+    var engine = try metal.MetalInferenceEngine.init(allocator, config);
+    defer engine.deinit();
+
+    // Allocate test matrices
+    const hidden_size: u32 = config.hidden_size;
+    const intermediate_size: u32 = config.intermediate_size;
+
+    // Test case 1: QKV projection [1, 5120] × [5120, 5120]
+    std.debug.print("\n=== Test 1: QKV Projection ===\n", .{});
+    std.debug.print("Matrix: [1, {}] × [{}, {}]\n", .{ hidden_size, hidden_size, hidden_size });
+
+    const input_qkv = try allocator.alloc(BF16, hidden_size);
+    defer allocator.free(input_qkv);
+    const weight_qkv = try allocator.alloc(BF16, hidden_size * hidden_size);
+    defer allocator.free(weight_qkv);
+    const output_qkv = try allocator.alloc(BF16, hidden_size);
+    defer allocator.free(output_qkv);
+
+    @memset(input_qkv, 0x3F80); // 1.0 in BF16
+    @memset(weight_qkv, 0x3F80);
+
+    // GPU matmul (using existing Metal kernel)
+    std.debug.print("\n--- GPU Matmul (Metal kernel) ---\n", .{});
+    const num_iters: usize = 100;
+    var gpu_total: i128 = 0;
+    var gpu_min: i128 = std.math.maxInt(i128);
+    var gpu_max: i128 = 0;
+
+    for (0..num_iters) |_| {
+        const start = std.time.nanoTimestamp();
+        // Call GPU matmul kernel directly
+        try engine.dispatchQKVProjectionNPU(input_qkv, weight_qkv, output_qkv, hidden_size);
+        const elapsed = std.time.nanoTimestamp() - start;
+        gpu_total += elapsed;
+        if (elapsed < gpu_min) gpu_min = elapsed;
+        if (elapsed > gpu_max) gpu_max = elapsed;
+    }
+
+    const gpu_avg = @divTrunc(gpu_total, @as(i128, num_iters));
+    const gpu_avg_ms = @as(f64, @floatFromInt(gpu_avg)) / 1_000_000.0;
+    const gpu_min_ms = @as(f64, @floatFromInt(gpu_min)) / 1_000_000.0;
+    const gpu_max_ms = @as(f64, @floatFromInt(gpu_max)) / 1_000_000.0;
+
+    std.debug.print("Average: {d:.3}ms\n", .{gpu_avg_ms});
+    std.debug.print("Min/Max: {d:.3}ms / {d:.3}ms\n", .{ gpu_min_ms, gpu_max_ms });
+
+    const qkv_ops = 2 * @as(u64, hidden_size) * hidden_size;
+    const gpu_gflops = @as(f64, @floatFromInt(qkv_ops)) / gpu_avg_ms / 1_000_000.0;
+    std.debug.print("Throughput: {d:.2} GFLOPS\n", .{gpu_gflops});
+
+    // NPU matmul (using MPSGraph)
+    std.debug.print("\n--- NPU Matmul (MPSGraph) ---\n", .{});
+    var npu_total: i128 = 0;
+    var npu_min: i128 = std.math.maxInt(i128);
+    var npu_max: i128 = 0;
+
+    for (0..num_iters) |_| {
+        const start = std.time.nanoTimestamp();
+        // Use MPSGraph matmul
+        const mps = engine.mps_engine orelse return error.MPSEngineNotInitialized;
+        try mps.matmulQKV(input_qkv, weight_qkv, output_qkv, hidden_size);
+        const elapsed = std.time.nanoTimestamp() - start;
+        npu_total += elapsed;
+        if (elapsed < npu_min) npu_min = elapsed;
+        if (elapsed > npu_max) npu_max = elapsed;
+    }
+
+    const npu_avg = @divTrunc(npu_total, @as(i128, num_iters));
+    const npu_avg_ms = @as(f64, @floatFromInt(npu_avg)) / 1_000_000.0;
+    const npu_min_ms = @as(f64, @floatFromInt(npu_min)) / 1_000_000.0;
+    const npu_max_ms = @as(f64, @floatFromInt(npu_max)) / 1_000_000.0;
+
+    std.debug.print("Average: {d:.3}ms\n", .{npu_avg_ms});
+    std.debug.print("Min/Max: {d:.3}ms / {d:.3}ms\n", .{ npu_min_ms, npu_max_ms });
+
+    const npu_gflops = @as(f64, @floatFromInt(qkv_ops)) / npu_avg_ms / 1_000_000.0;
+    std.debug.print("Throughput: {d:.2} GFLOPS\n", .{npu_gflops});
+
+    // Comparison
+    std.debug.print("\n--- Comparison ---\n", .{});
+    if (npu_avg_ms < gpu_avg_ms) {
+        const speedup = gpu_avg_ms / npu_avg_ms;
+        std.debug.print("✓ NPU is {d:.2}x faster!\n", .{speedup});
+    } else {
+        const slowdown = npu_avg_ms / gpu_avg_ms;
+        std.debug.print("✗ NPU is {d:.2}x slower\n", .{slowdown});
+        std.debug.print("  (Likely MPSGraph overhead or not using ANE)\n", .{});
+    }
+
+    // Test case 2: FFN Gate projection [1, 5120] × [5120, 27648]
+    std.debug.print("\n\n=== Test 2: FFN Gate Projection ===\n", .{});
+    std.debug.print("Matrix: [1, {}] × [{}, {}]\n", .{ hidden_size, hidden_size, intermediate_size });
+
+    const input_ffn = try allocator.alloc(BF16, hidden_size);
+    defer allocator.free(input_ffn);
+    const weight_ffn = try allocator.alloc(BF16, hidden_size * intermediate_size);
+    defer allocator.free(weight_ffn);
+    const output_ffn = try allocator.alloc(BF16, intermediate_size);
+    defer allocator.free(output_ffn);
+
+    @memset(input_ffn, 0x3F80);
+    @memset(weight_ffn, 0x3F80);
+
+    // GPU matmul
+    std.debug.print("\n--- GPU Matmul ---\n", .{});
+    gpu_total = 0;
+    gpu_min = std.math.maxInt(i128);
+    gpu_max = 0;
+
+    for (0..num_iters) |_| {
+        const start = std.time.nanoTimestamp();
+        try engine.dispatchFFNGateNPU(input_ffn, weight_ffn, output_ffn, hidden_size, intermediate_size);
+        const elapsed = std.time.nanoTimestamp() - start;
+        gpu_total += elapsed;
+        if (elapsed < gpu_min) gpu_min = elapsed;
+        if (elapsed > gpu_max) gpu_max = elapsed;
+    }
+
+    const gpu_ffn_avg = @divTrunc(gpu_total, @as(i128, num_iters));
+    const gpu_ffn_ms = @as(f64, @floatFromInt(gpu_ffn_avg)) / 1_000_000.0;
+    std.debug.print("Average: {d:.3}ms\n", .{gpu_ffn_ms});
+
+    const ffn_ops = 2 * @as(u64, hidden_size) * intermediate_size;
+    const gpu_ffn_gflops = @as(f64, @floatFromInt(ffn_ops)) / gpu_ffn_ms / 1_000_000.0;
+    std.debug.print("Throughput: {d:.2} GFLOPS\n", .{gpu_ffn_gflops});
+
+    // NPU matmul
+    std.debug.print("\n--- NPU Matmul ---\n", .{});
+    npu_total = 0;
+    npu_min = std.math.maxInt(i128);
+    npu_max = 0;
+
+    for (0..num_iters) |_| {
+        const start = std.time.nanoTimestamp();
+        const mps = engine.mps_engine orelse return error.MPSEngineNotInitialized;
+        try mps.matmulFFNGate(input_ffn, weight_ffn, output_ffn, hidden_size, intermediate_size);
+        const elapsed = std.time.nanoTimestamp() - start;
+        npu_total += elapsed;
+        if (elapsed < npu_min) npu_min = elapsed;
+        if (elapsed > npu_max) npu_max = elapsed;
+    }
+
+    const npu_ffn_avg = @divTrunc(npu_total, @as(i128, num_iters));
+    const npu_ffn_ms = @as(f64, @floatFromInt(npu_ffn_avg)) / 1_000_000.0;
+    std.debug.print("Average: {d:.3}ms\n", .{npu_ffn_ms});
+
+    const npu_ffn_gflops = @as(f64, @floatFromInt(ffn_ops)) / npu_ffn_ms / 1_000_000.0;
+    std.debug.print("Throughput: {d:.2} GFLOPS\n", .{npu_ffn_gflops});
+
+    // Comparison
+    std.debug.print("\n--- Comparison ---\n", .{});
+    if (npu_ffn_ms < gpu_ffn_ms) {
+        const speedup = gpu_ffn_ms / npu_ffn_ms;
+        std.debug.print("✓ NPU is {d:.2}x faster!\n", .{speedup});
+    } else {
+        const slowdown = npu_ffn_ms / gpu_ffn_ms;
+        std.debug.print("✗ NPU is {d:.2}x slower\n", .{slowdown});
+    }
+
+    std.debug.print("\n=== Conclusion ===\n", .{});
+    std.debug.print("If NPU is slower, it's likely:\n", .{});
+    std.debug.print("1. MPSGraph overhead (NDArrays, feeds, dicts)\n", .{});
+    std.debug.print("2. MPSGraph routing to GPU, not ANE\n", .{});
+    std.debug.print("3. ANE warmup needed\n", .{});
+    std.debug.print("\nNext steps:\n", .{});
+    std.debug.print("- Use powermetrics to verify ANE usage\n", .{});
+    std.debug.print("- Try BNNS instead of MPSGraph\n", .{});
+    std.debug.print("- Or accept GPU is better for streaming inference\n", .{});
+}

