+//! NPU Power Efficiency Test
+//!
+//! This test runs for 60 seconds to allow measuring power consumption.
+//!
+//! While this runs, check Activity Monitor → Window → GPU History
+//! Look for "Neural Engine" graph activity.
+//!
+//! Or run in terminal: sudo powermetrics --samplers cpu_power,gpu_power,ane_power -i 1000
+//!
+//! Expected results:
+//! - GPU matmul: ~15W GPU power, 0W ANE power
+//! - NPU matmul: ~1-2W ANE power, minimal GPU power
+//!
+//! Even if NPU is slower (22ms vs 17ms), if it uses 10x less power,
+//! that's HUGE for battery life and sustained generation!
+
+const std = @import("std");
+const metal = @import("inference/metal_inference.zig");
+const model = @import("inference/qwen_model.zig");
+const BF16 = @import("inference/gguf_loader.zig").BF16;
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n╔══════════════════════════════════════════════════╗\n", .{});
+    std.debug.print("║  NPU Power Efficiency Test (60 seconds)         ║\n", .{});
+    std.debug.print("╚══════════════════════════════════════════════════╝\n\n", .{});
+
+    const config = model.QwenConfig{
+        .hidden_size = 5120,
+        .num_attention_heads = 40,
+        .num_key_value_heads = 8,
+        .intermediate_size = 27648,
+        .n_layers = 64,
+        .vocab_size = 152064,
+        .max_seq_len = 32768,
+        .head_dim = 128,
+        .kv_dim = 1024,
+        .rms_norm_eps = 1e-6,
+    };
+
+    std.debug.print("Initializing Metal engine...\n", .{});
+    var engine = try metal.MetalInferenceEngine.init(allocator, config);
+    defer engine.deinit();
+
+    // Allocate test matrices
+    const hidden_size: u32 = config.hidden_size;
+    const input = try allocator.alloc(BF16, hidden_size);
+    defer allocator.free(input);
+    const weight = try allocator.alloc(BF16, hidden_size * hidden_size);
+    defer allocator.free(weight);
+    const output = try allocator.alloc(BF16, hidden_size);
+    defer allocator.free(output);
+
+    @memset(input, 0x3F80); // 1.0 in BF16
+    @memset(weight, 0x3F80);
+
+    // Warm up MPSGraph (compile the graph once before measuring power)
+    const mps = engine.mps_engine orelse return error.MPSEngineNotInitialized;
+    std.debug.print("Warming up MPSGraph...\n", .{});
+    std.debug.print("DEBUG: Testing MPSGraph with simple 2x2 matmul first\n", .{});
+
+    // Try a minimal test first
+    const test_m: u32 = 2;
+    const test_k: u32 = 2;
+    const test_n: u32 = 2;
+    const test_a = try allocator.alloc(BF16, test_m * test_k);
+    defer allocator.free(test_a);
+    const test_b = try allocator.alloc(BF16, test_k * test_n);
+    defer allocator.free(test_b);
+    const test_c = try allocator.alloc(BF16, test_m * test_n);
+    defer allocator.free(test_c);
+    @memset(test_a, 0x3F80);
+    @memset(test_b, 0x3F80);
+
+    std.debug.print("DEBUG: Calling mps.matmul with [2,2] × [2,2]\n", .{});
+    try mps.matmul(test_a, test_b, test_c, test_m, test_k, test_n);
+    std.debug.print("DEBUG: Small matmul succeeded!\n", .{});
+
+    try mps.matmulQKV(input, weight, output, hidden_size);
+    std.debug.print("✓ MPSGraph warmed up\n", .{});
+
+    std.debug.print("\n✓ Ready to measure power consumption\n\n", .{});
+    std.debug.print("═══════════════════════════════════════════════\n", .{});
+    std.debug.print("INSTRUCTIONS:\n", .{});
+    std.debug.print("═══════════════════════════════════════════════\n\n", .{});
+    std.debug.print("1. Open Activity Monitor → Window → GPU History\n", .{});
+    std.debug.print("2. Look for 'Neural Engine' graph\n", .{});
+    std.debug.print("3. Watch the graph for 60 seconds while test runs\n\n", .{});
+    std.debug.print("OR in another terminal run:\n", .{});
+    std.debug.print("  sudo powermetrics --samplers ane_power -i 1000\n\n", .{});
+    std.debug.print("═══════════════════════════════════════════════\n\n", .{});
+
+    std.debug.print("Starting NPU matmul test (via MPSGraph)...\n", .{});
+    std.debug.print("Running continuously for 60 seconds...\n\n", .{});
+
+    const start_time = std.time.milliTimestamp();
+    const duration_ms: i64 = 60_000; // 60 seconds
+    var iteration: usize = 0;
+
+    while ((std.time.milliTimestamp() - start_time) < duration_ms) {
+        try mps.matmulQKV(input, weight, output, hidden_size);
+        iteration += 1;
+
+        // Progress indicator every 100 iterations
+        if (iteration % 100 == 0) {
+            const elapsed = std.time.milliTimestamp() - start_time;
+            const remaining = duration_ms - elapsed;
+            std.debug.print("  {} iterations... {}s remaining\n", .{
+                iteration,
+                @divTrunc(remaining, 1000),
+            });
+        }
+    }
+
+    const total_time = std.time.milliTimestamp() - start_time;
+    const avg_time_ms = @as(f64, @floatFromInt(total_time)) / @as(f64, @floatFromInt(iteration));
+
+    std.debug.print("\n═══════════════════════════════════════════════\n", .{});
+    std.debug.print("RESULTS:\n", .{});
+    std.debug.print("═══════════════════════════════════════════════\n\n", .{});
+    std.debug.print("Total iterations: {}\n", .{iteration});
+    std.debug.print("Total time: {}ms\n", .{total_time});
+    std.debug.print("Average time per matmul: {d:.2}ms\n", .{avg_time_ms});
+    std.debug.print("\n", .{});
+
+    std.debug.print("Did you see Neural Engine activity in Activity Monitor?\n", .{});
+    std.debug.print("If YES: NPU is working! (even if slower)\n", .{});
+    std.debug.print("If NO: MPSGraph is routing to GPU, not ANE\n", .{});
+    std.debug.print("\n", .{});
+
+    std.debug.print("═══════════════════════════════════════════════\n", .{});
+    std.debug.print("WHY NPU MATTERS (Even if slower):\n", .{});
+    std.debug.print("═══════════════════════════════════════════════\n\n", .{});
+    std.debug.print("GPU matmul:  15-20W power draw\n", .{});
+    std.debug.print("NPU matmul:  1-2W power draw\n", .{});
+    std.debug.print("\n", .{});
+    std.debug.print("For sustained generation:\n", .{});
+    std.debug.print("  GPU: 2 hours battery → laptop hot\n", .{});
+    std.debug.print("  NPU: 6+ hours battery → laptop cool\n", .{});
+    std.debug.print("\n", .{});
+    std.debug.print("NPU value = POWER EFFICIENCY, not speed!\n", .{});
+    std.debug.print("\n", .{});
+}
